import os
import sys
import subprocess
import shutil
from pathlib import Path
from zipfile import ZipFile, ZIP_DEFLATED

ROOT = Path(__file__).resolve().parent
VENV_DIR = ROOT / ".venv"
REQ_FILE = ROOT / "requirements.txt"
DIST_DIR = ROOT / "dist"
PACKAGE_NAME = "deployment_package.zip"


def run(cmd, cwd=ROOT, env=None):
    print(f"Running: {' '.join(cmd)}")
    subprocess.run(cmd, cwd=cwd, env=env, check=True)


def python_executable():
    if os.name == "nt":
        return VENV_DIR / "Scripts" / "python.exe"
    return VENV_DIR / "bin" / "python"


def ensure_venv():
    py = python_executable()
    if py.exists():
        return py
    run([sys.executable, "-m", "venv", str(VENV_DIR)])
    return py


def install_dependencies(py):
    if REQ_FILE.exists():
        run([str(py), "-m", "pip", "install", "--upgrade", "pip"])
        run([str(py), "-m", "pip", "install", "-r", str(REQ_FILE)])


def run_tests(py):
    test_cmd = None
    if (ROOT / "pytest.ini").exists() or (ROOT / "tests").exists():
        test_cmd = [str(py), "-m", "pytest", "-q"]
    elif (ROOT / "unittest").exists():
        test_cmd = [str(py), "-m", "unittest", "discover", "-v"]
    else:
        test_cmd = [str(py), "-m", "pytest", "-q"]
    run(test_cmd)


def package_app():
    DIST_DIR.mkdir(exist_ok=True)
    package_path = DIST_DIR / PACKAGE_NAME
    if package_path.exists():
        package_path.unlink()

    exclude_dirs = {
        ".git",
        ".venv",
        "__pycache__",
        ".pytest_cache",
        "dist",
        "build",
        ".mypy_cache",
        ".tox",
    }

    with ZipFile(package_path, "w", compression=ZIP_DEFLATED) as zf:
        for path in ROOT.rglob("*"):
            rel = path.relative_to(ROOT)

            if any(part in exclude_dirs for part in rel.parts):
                continue
            if path.is_dir():
                continue
            if path == package_path:
                continue

            zf.write(path, rel.as_posix())

    print(f"Packaged to {package_path}")


def main():
    py = ensure_venv()
    install_dependencies(py)
    run_tests(py)
    package_app()
    print("Deployment workflow completed successfully.")


if __name__ == "__main__":
    try:
        main()
    except subprocess.CalledProcessError as e:
        print(f"Command failed with exit code {e.returncode}", file=sys.stderr)
        sys.exit(e.returncode)
    except Exception as e:
        print(f"Deployment failed: {e}", file=sys.stderr)
        sys.exit(1)